CREATE TABLE IF NOT EXISTS "Employees" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "Username" character varying(50) NOT NULL,
    "Password" character varying(100) NOT NULL,
    "DisplayName" character varying(120) NOT NULL
);

CREATE UNIQUE INDEX IF NOT EXISTS "IX_Employees_Username" ON "Employees" ("Username");

CREATE TABLE IF NOT EXISTS "Customers" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "FirstName" character varying(80) NOT NULL,
    "LastName" character varying(80) NOT NULL,
    "Phone" character varying(30),
    "Email" character varying(160),
    "Notes" character varying(240)
);

CREATE TABLE IF NOT EXISTS "Vehicles" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "CustomerId" integer NOT NULL REFERENCES "Customers" ("Id") ON DELETE CASCADE,
    "Year" integer NOT NULL,
    "Make" character varying(80) NOT NULL,
    "Model" character varying(80) NOT NULL,
    "Color" character varying(40),
    "LicensePlate" character varying(40),
    "Vin" character varying(17)
);

CREATE INDEX IF NOT EXISTS "IX_Vehicles_CustomerId" ON "Vehicles" ("CustomerId");

CREATE TABLE IF NOT EXISTS "WorkOrders" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "VehicleId" integer NOT NULL REFERENCES "Vehicles" ("Id") ON DELETE CASCADE,
    "Complaint" character varying(120) NOT NULL,
    "TechnicianNotes" character varying(1000),
    "Status" character varying(32) NOT NULL,
    "OpenedOn" date NOT NULL,
    "PromisedOn" date
);

CREATE INDEX IF NOT EXISTS "IX_WorkOrders_VehicleId" ON "WorkOrders" ("VehicleId");

CREATE TABLE IF NOT EXISTS "WorkOrderLineItems" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "WorkOrderId" integer NOT NULL REFERENCES "WorkOrders" ("Id") ON DELETE CASCADE,
    "Description" character varying(160) NOT NULL,
    "Quantity" numeric(10,2) NOT NULL,
    "UnitPrice" numeric(10,2) NOT NULL
);

CREATE INDEX IF NOT EXISTS "IX_WorkOrderLineItems_WorkOrderId" ON "WorkOrderLineItems" ("WorkOrderId");

